// ─── EDITAR ESTAS DOS LÍNEAS ANTES DE ACTIVAR ───────────────
const SUPABASE_KEY = 'PEGAR_SERVICE_ROLE_KEY_AQUI';
const RESEND_KEY   = 'PEGAR_RESEND_API_KEY_AQUI';
// ─────────────────────────────────────────────────────────────

const SUPABASE_URL = 'https://rflfsbrdmgaidhvbuvwb.supabase.co';
const FROM_EMAIL   = 'DidactIA Briefing <briefing@didactia.eu>';

const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const now = new Date();
const today = fmt(now);
const yd = new Date(now);
yd.setDate(yd.getDate() - 1);
const yesterday = fmt(yd);
const fechaLegible = now.toLocaleDateString('es-ES', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

return [{ json: { SUPABASE_URL, SUPABASE_KEY, RESEND_KEY, FROM_EMAIL, today, yesterday, fechaLegible } }];

const cfg  = $('Config y fechas').first().json;
const ad   = Array.isArray($('Get Admins').first().json)        ? $('Get Admins').first().json        : [];
const su   = Array.isArray($('Get Sustituciones').first().json)  ? $('Get Sustituciones').first().json  : [];
const au   = Array.isArray($('Get Ausencias').first().json)      ? $('Get Ausencias').first().json      : [];
const co   = Array.isArray($('Get Comedor').first().json)        ? $('Get Comedor').first().json        : [];

// Agrupar por centro_id
const sustBC = {}, ausBC = {}, comeBC = {};
su.forEach(s => { if (!sustBC[s.centro_id]) sustBC[s.centro_id] = []; sustBC[s.centro_id].push(s); });
au.forEach(a => { if (!ausBC[a.centro_id])  ausBC[a.centro_id]  = []; ausBC[a.centro_id].push(a);  });
co.forEach(r => { comeBC[r.centro_id] = (comeBC[r.centro_id] || 0) + 1; });

const TIPOS = {
  baja_medica: 'Baja medica', permiso: 'Permiso',
  asunto_propio: 'Asunto propio', formacion: 'Formacion',
  sindical: 'Sindical', otros: 'Otros'
};

// Verde si 0, naranja si poco, rojo si mucho
const clr = (n, a, b) => n === 0 ? '#1e6b3a' : n < a ? '#e65100' : '#c62828';

return ad.filter(admin => admin.email).map(admin => {
  const cId   = admin.centro_id;
  const cNom  = (admin.centros && admin.centros.nombre) || 'Centro';
  const mySust = sustBC[cId] || [];
  const myAus  = ausBC[cId]  || [];
  const nCome  = comeBC[cId] || 0;

  const TH = `padding:8px 12px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.04em;color:#666;background:#f8f9fa;border-bottom:2px solid #e8e8e8;text-align:left;`;
  const TD = `padding:9px 12px;color:#333;font-size:13px;border-bottom:1px solid #f0f0f0;`;
  const sinAsignar = `<span style='color:#c62828;font-weight:600;'>Sin asignar</span>`;

  const sRows = mySust.length === 0
    ? `<tr><td colspan='5' style='${TD}text-align:center;color:#888;padding:16px;'>No hay sustituciones pendientes hoy</td></tr>`
    : mySust.map(s =>
        `<tr><td style='${TD}'>${s.tramo||'—'}</td>` +
        `<td style='${TD}white-space:nowrap;'>${s.hora_inicio||'—'}–${s.hora_fin||'—'}</td>` +
        `<td style='${TD}'>${s.grupo_horario||'—'}</td>` +
        `<td style='${TD}'>${s.profesor_ausente||'—'}</td>` +
        `<td style='${TD}'>${s.profesor_sustituto||sinAsignar}</td></tr>`
      ).join('');

  const aRows = myAus.length === 0
    ? `<tr><td colspan='3' style='${TD}text-align:center;color:#888;padding:16px;'>No hay ausencias aprobadas hoy</td></tr>`
    : myAus.map(a => {
        const fStr = (a.fecha_fin && a.fecha_fin !== a.fecha)
          ? `${a.fecha} a ${a.fecha_fin}` : (a.fecha||'—');
        return `<tr>` +
          `<td style='${TD}'>${(a.profiles && a.profiles.full_name)||'—'}</td>` +
          `<td style='${TD}'>${TIPOS[a.tipo]||a.tipo||'—'}</td>` +
          `<td style='${TD}white-space:nowrap;'>${fStr}</td></tr>`;
      }).join('');

  const html =
    `<!DOCTYPE html><html lang='es'><head><meta charset='UTF-8'>` +
    `<meta name='viewport' content='width=device-width,initial-scale=1'>` +
    `<title>Briefing DidactIA</title></head>` +
    `<body style='margin:0;padding:0;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,sans-serif;'>` +
    `<div style='max-width:640px;margin:24px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,0.09);'>` +

    `<div style='background:#1a73e8;padding:28px 32px 24px;'>` +
    `<div style='font-size:11px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(255,255,255,0.65);margin-bottom:6px;'>DidactIA - Briefing matutino</div>` +
    `<div style='font-size:20px;font-weight:700;color:#fff;'>${cNom}</div>` +
    `<div style='font-size:14px;color:rgba(255,255,255,0.85);margin-top:5px;text-transform:capitalize;'>${cfg.fechaLegible}</div>` +
    `</div>` +

    `<table width='100%' style='border-collapse:collapse;border-bottom:1px solid #e8e8e8;'><tr>` +
    `<td width='33%' style='padding:20px;text-align:center;border-right:1px solid #e8e8e8;'>` +
    `<div style='font-size:40px;font-weight:700;color:${clr(mySust.length,1,5)};line-height:1;'>${mySust.length}</div>` +
    `<div style='font-size:11px;color:#888;margin-top:5px;text-transform:uppercase;'>Sust. pendientes</div></td>` +
    `<td width='33%' style='padding:20px;text-align:center;border-right:1px solid #e8e8e8;'>` +
    `<div style='font-size:40px;font-weight:700;color:${clr(myAus.length,1,4)};line-height:1;'>${myAus.length}</div>` +
    `<div style='font-size:11px;color:#888;margin-top:5px;text-transform:uppercase;'>Ausencias hoy</div></td>` +
    `<td width='33%' style='padding:20px;text-align:center;'>` +
    `<div style='font-size:40px;font-weight:700;color:#333;line-height:1;'>${nCome}</div>` +
    `<div style='font-size:11px;color:#888;margin-top:5px;text-transform:uppercase;'>Comensales ayer</div></td>` +
    `</tr></table>` +

    `<div style='padding:24px 32px 8px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Sustituciones pendientes de cubrir</div>` +
    `<table width='100%' style='border-collapse:collapse;'><thead><tr>` +
    `<th style='${TH}'>Tramo</th><th style='${TH}'>Hora</th><th style='${TH}'>Grupo</th>` +
    `<th style='${TH}'>Ausente</th><th style='${TH}'>Sustituto</th>` +
    `</tr></thead><tbody>${sRows}</tbody></table></div>` +

    `<div style='padding:16px 32px 24px;'>` +
    `<div style='font-size:11px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;color:#555;margin-bottom:12px;'>Ausencias aprobadas hoy</div>` +
    `<table width='100%' style='border-collapse:collapse;'><thead><tr>` +
    `<th style='${TH}'>Profesor/a</th><th style='${TH}'>Tipo</th><th style='${TH}'>Periodo</th>` +
    `</tr></thead><tbody>${aRows}</tbody></table></div>` +

    `<div style='padding:14px 32px;border-top:1px solid #e8e8e8;background:#fafafa;'>` +
    `<div style='font-size:11px;color:#aaa;'>Generado por <strong style='color:#1a73e8;'>DidactIA</strong> - didactia.eu - No respondas a este email</div>` +
    `</div></div></body></html>`;

  return { json: {
    to:        admin.email,
    subject:   `DidactIA - Briefing del ${cfg.fechaLegible} - ${cNom}`,
    html,
    fromEmail: cfg.FROM_EMAIL,
    resendKey: cfg.RESEND_KEY
  }};
});
